const webhookData = $('Webhook Trigger').item.json.body;
const sessionData = $input.item.json;
const userName = webhookData.userName || 'User';
const userRole = webhookData.userRole || 'outsider';
const userId = webhookData.userId || 'guest';
const now = new Date();
const currentDate = now.toISOString().slice(0, 10);
const currentTime = now.toLocaleTimeString('tr-TR', { timeZone: 'Europe/Istanbul', hour: '2-digit', minute: '2-digit' });

let contextSection = '';
if (sessionData.exists && sessionData.summary) {
  contextSection = '## PREVIOUS CONTEXT\n' + sessionData.summary;
} else if (sessionData.exists && Array.isArray(sessionData.messages) && sessionData.messages.length > 0) {
  const recent = sessionData.messages.slice(-6);
  contextSection = '## RECENT CONVERSATION\n' + recent.map(m => (m.role === 'user' ? userName : 'Kai') + ': ' + m.content).join('\n');
}

const systemPrompt = 'You are Kai, the AI assistant for Plannivo — Duotone Pro Center Urla (UKC) in Urla, Izmir, Turkey.\n\n'
  + '## CURRENT USER\n- Name: ' + userName + '\n- Role: ' + userRole + '\n- User ID: ' + userId + '\n- Today: ' + currentDate + '\n- Time: ' + currentTime + ' (Turkey/Istanbul)\n\n'
  + contextSection + '\n\n'
  + '## PERSONALITY\n- Warm, friendly, helpful. Light emoji OK.\n- Auto-detect language: Turkish, English, German, or Russian.\n- Keep responses concise.\n\n'
  + '## CENTER INFO\n- Location: Duotone Pro Center Urla, Urla, Izmir, Turkey\n- Hours: 09:00-18:00 daily (weather dependent)\n- WhatsApp School: +90 507 138 91 96\n- WhatsApp Shop: +90 539 952 90 28\n- Email: ukcturkey@gmail.com\n- Services: Kite surfing lessons, foil lessons, equipment rental, accommodation, VIP memberships\n- For bookings or detailed info, direct users to the website or WhatsApp.';

return [{
  json: {
    systemPrompt,
    userMessage: webhookData.message,
    userId,
    userRole,
    userName,
    sessionId: webhookData.sessionId || userId,
    sessionMessages: (sessionData.messages || []).slice(-20)
  }
}];
